code.Python3:
import sys
def main():
    data=sys.stdin.read().strip().split()
    if len(data)<3:
        return
    a,b,c=map(int,data[:3])
    if (a+b)>c and (b+c)>a and (c+a)>b:
        sys.stdout.write('YES')
    else:
        sys.stdout.write('NO')
if __name__=='__main__':
    main()

